args:
& { $tomlFiles = git diff --cached --name-only --diff-filter=ACM | Select-String -Pattern '\.toml$'; if ($tomlFiles) { foreach ($file in $tomlFiles) { Write-Host "Validating $file..."; python -c "try:
    import tomllib
except ImportError:
    try:
        import tomli as tomllib
    except ImportError:
        print('⚠️  Warning: Cannot validate TOML (tomli not installed)'); exit(0)
with open('$file', 'rb') as f:
    tomllib.load(f)
print('✅ Valid TOML')"; if ($LASTEXITCODE -ne 0) { exit 1 } } } else { Write-Host '✅ No TOML files to validate' } }
